package main

import (
	"fmt"
	"strings"
	"strconv"
)

func parseEmbed(s string) ([]string, error) {
	s = strings.TrimPrefix(s, "//go:embed")
	var args []string
	for len(s) > 0 {
		s = strings.TrimLeft(s, " \t")
		if len(s) == 0 {
			break
		}
		if s[0] == '"' || s[0] == '`' {
			quote := s[0]
			end := strings.Index(s[1:], string(quote))
			if end < 0 {
				return nil, fmt.Errorf("invalid quote")
			}
			val, err := strconv.Unquote(s[:end+2])
			if err != nil {
				return nil, err
			}
			args = append(args, val)
			s = s[end+2:]
		} else {
			i := 0
			for i < len(s) && s[i] != ' ' && s[i] != '\t' {
				i++
			}
			args = append(args, s[:i])
			s = s[i:]
		}
	}
	return args, nil
}
func main() {
	fmt.Println(parseEmbed(`//go:embed a b "c d" `+"`e f`"))
}
