package interp

import (
	"bytes"
	"errors"
	"io/fs"
	"path"
	"sort"
	"strings"
	"time"
)

type embedFS struct {
	files map[string]*embedFile
}

type embedFile struct {
	name string
	data []byte
	dir  bool
}

func (f *embedFS) Open(name string) (fs.File, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrInvalid}
	}
	file, ok := f.files[name]
	if !ok {
		return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrNotExist}
	}
	if file.dir {
		var entries []fs.DirEntry
		for p, child := range f.files {
			if path.Dir(p) == name && p != name {
				entries = append(entries, &embedDirEntry{child})
			}
		}
		sort.Slice(entries, func(i, j int) bool { return entries[i].Name() < entries[j].Name() })
		return &embedOpenDir{embedFileInfo{file}, entries, 0}, nil
	}
	return &embedOpenFile{embedFileInfo{file}, bytes.NewReader(file.data)}, nil
}

func (f *embedFS) ReadDir(name string) ([]fs.DirEntry, error) {
	file, err := f.Open(name)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	dir, ok := file.(fs.ReadDirFile)
	if !ok {
		return nil, &fs.PathError{Op: "readdir", Path: name, Err: errors.New("not a directory")}
	}
	return dir.ReadDir(-1)
}

func (f *embedFS) ReadFile(name string) ([]byte, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrInvalid}
	}
	file, ok := f.files[name]
	if !ok {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrNotExist}
	}
	if file.dir {
		return nil, &fs.PathError{Op: "read", Path: name, Err: errors.New("is a directory")}
	}
	return append([]byte(nil), file.data...), nil // independent copy
}

type embedFileInfo struct{ *embedFile }

func (f embedFileInfo) Name() string       { return path.Base(f.name) }
func (f embedFileInfo) Size() int64        { return int64(len(f.data)) }
func (f embedFileInfo) Mode() fs.FileMode  { if f.dir { return fs.ModeDir | 0555 }; return 0444 }
func (f embedFileInfo) ModTime() time.Time { return time.Time{} }
func (f embedFileInfo) IsDir() bool        { return f.dir }
func (f embedFileInfo) Sys() any           { return nil }

type embedDirEntry struct{ *embedFile }

func (d embedDirEntry) Name() string               { return path.Base(d.name) }
func (d embedDirEntry) IsDir() bool                { return d.dir }
func (d embedDirEntry) Type() fs.FileMode          { if d.dir { return fs.ModeDir }; return 0 }
func (d embedDirEntry) Info() (fs.FileInfo, error) { return embedFileInfo{d.embedFile}, nil }

type embedOpenFile struct {
	embedFileInfo
	*bytes.Reader
}

func (f *embedOpenFile) Stat() (fs.FileInfo, error) { return f.embedFileInfo, nil }
func (f *embedOpenFile) Close() error               { return nil }

type embedOpenDir struct {
	embedFileInfo
	entries []fs.DirEntry
	offset  int
}

func (d *embedOpenDir) Stat() (fs.FileInfo, error) { return d.embedFileInfo, nil }
func (d *embedOpenDir) Close() error               { return nil }
func (d *embedOpenDir) Read([]byte) (int, error)   { return 0, &fs.PathError{Op: "read", Path: d.name, Err: errors.New("is a directory")} }
func (d *embedOpenDir) ReadDir(n int) ([]fs.DirEntry, error) {
	if n <= 0 {
		res := d.entries[d.offset:]
		d.offset = len(d.entries)
		return res, nil
	}
	if d.offset >= len(d.entries) {
		return nil, fs.ErrEOF // No more entries? fs package says io.EOF or nil? ReadDir returns nil, nil for EOF if n <= 0, but io.EOF if n > 0.
	}
	end := d.offset + n
	if end > len(d.entries) {
		end = len(d.entries)
	}
	res := d.entries[d.offset:end]
	d.offset = end
	return res, nil
}
