cat << 'EOF' >> interp/embed.go

func resolveEmbed(fsys fs.FS, baseDir string, patterns []string) (map[string][]byte, error) {
	files := make(map[string][]byte)
	for _, pattern := range patterns {
		all := strings.HasPrefix(pattern, "all:")
		if all {
			pattern = pattern[4:]
		}

		// Wait, patterns are evaluated relative to baseDir.
		// Go's go:embed resolves directory as directory contents.
		// This is just a basic implementation. We can use fs.WalkDir on the baseDir.

		var matchFound bool
		err := fs.WalkDir(fsys, baseDir, func(p string, d fs.DirEntry, err error) error {
			if err != nil {
				return err
			}
			rel, err := path.Rel(baseDir, p)
			if err != nil || rel == "." || rel == ".." {
				return nil
			}

			// check if `rel` matches `pattern` or if it's inside a matched directory.
			// Go embed matches pattern against the relative path.
			// For simplicity, let's assume direct path.Match on rel or its prefixes.

			// To perfectly implement go:embed we'd need a robust matcher,
			// but a basic match is:
			matched, _ := path.Match(pattern, rel)
			if !matched {
				// if pattern matches a parent dir, it includes this file
				parts := strings.Split(rel, "/")
				for i := 1; i <= len(parts); i++ {
					m, _ := path.Match(pattern, strings.Join(parts[:i], "/"))
					if m {
						matched = true
						break
					}
				}
			}

			if !matched {
				return nil
			}

			// skip hidden files unless `all:` or directly matched
			if !all && !matched { // matched means it directly matched, wait, if parent matched, it's still false if we don't have all?
				// standard go: if a directory is matched, files starting with . or _ are excluded unless all: is used.
				name := d.Name()
				if strings.HasPrefix(name, ".") || strings.HasPrefix(name, "_") {
					// if directly matched by pattern, include it, else skip
					m, _ := path.Match(pattern, rel)
					if !m {
						if d.IsDir() {
							return fs.SkipDir
						}
						return nil
					}
				}
			}

			matchFound = true
			if !d.IsDir() {
				b, err := fs.ReadFile(fsys, p)
				if err != nil {
					return err
				}
				files[rel] = b
			}
			return nil
		})
		if err != nil {
			return nil, err
		}
		if !matchFound {
			return nil, fmt.Errorf("pattern %s: no matching files found", pattern)
		}
	}
	return files, nil
}
